import React from 'react';

function ChatWindow({ messages, input, setInput, onSend }) {
    return (
        <div className="flex-1 flex flex-col p-4">
            <div className="flex-1 overflow-y-auto space-y-4 mb-4">
                {messages.map((msg, idx) => (
                    <div key={idx} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                        <div className={`message-bubble ${msg.sender === 'user' ? 'bg-gradient-to-r from-pink-400 to-orange-300 text-white' : 'bg-white/90 border border-purple-200 text-gray-800'}`}>
                            {msg.text}
                        </div>
                    </div>
                ))}
            </div>
            <div className="flex gap-2">
                <input
                    type="text"
                    value={input}
                    onChange={e => setInput(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && onSend()}
                    placeholder="输入你的问题，如：生成5道小数乘法作业"
                    className="flex-1 input-field"
                />
                <button onClick={onSend} className="send-btn">发送</button>
            </div>
        </div>
    );
}

export default ChatWindow;
